import React from 'react';
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import FacebookFeed from './FacebookFeed';

function About() {
  return (
    <Container fluid className="about section">
      <Row className="justify-content-center">
        <Col lg={4} md={{ span: 4, order: 2 }} sm={12}>
          <h2 className="title">What is Track and Rally?</h2>
          <p style={{ marginBottom: "4rem" }}>
            Founded by racers (Dave Gregory and Jeff Berlin), Track and Rally was started to help provide racers the opportunity for more seat time.&nbsp;Our goal is to connect racers to more events, so they can improve their skills and gain exposure for sponsorships.&nbsp;Whether you are looking for an Autocross, Rallycross, Stage Rally, or Track Day, we have an event for you!
          </p>
        </Col>
        <Col lg={4} md={{ span: 4, order: 1 }} sm={12}>
          <FacebookFeed />
        </Col>
      </Row>
    </Container>
  )
}

export default About;
